sql.where:
d.is_deleted = 0

    AND d.name LIKE CONCAT('%', #{name}, '%')


    AND d.type = #{type}


    AND d.region = #{region}

mapper.select:
SELECT
FROM dorm_info d LEFT JOIN room_info r ON r.dorm_id = d.id AND r.is_deleted = 0
GROUP BY d.id, d.name, d.address, d.type, d.layout, d.region, d.total_rooms, d.status ORDER BY d.id ASC LIMIT #{pageSize} OFFSET #{offset}
